document.addEventListener(`DOMContentLoaded`,()=>{document.querySelectorAll(`[data-countdown]`).forEach(e=>{let t=parseInt(e.getAttribute(`data-countdown`),10),n=()=>{if(t<=0){e.textContent=`00:00:00`;return}e.textContent=`${Math.floor(t/3600).toString().padStart(2,`0`)}:${Math.floor(t%3600/60).toString().padStart(2,`0`)}:${(t%60).toString().padStart(2,`0`)}`,t--};n(),setInterval(n,1e3)})});